"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[836],{41342:e=>{e.exports=JSON.parse('{"functions":[],"properties":[{"name":"ControllerType","desc":"Passed as `DefineConfig.Type`. `Relative` sizes dynamically toward `RecommendedVoxelSize`\\nand splits multi-part Shatter calls across the Workers Actor pool; `Absolute` uses a fixed\\n`VoxelSize` and never threads.","lua_type":"{Relative: \\"Relative\\", Absolute: \\"Absolute\\"}","source":{"line":20,"path":"src/_Core/Enums.luau"}},{"name":"RuntimeType","desc":"Passed as `DefineConfig.RuntimeType`. `Instant` (default) runs every `Shatter` call the\\nmoment it\'s called; `Timeline` queues calls until `Controller:Start()` flushes them in order.","lua_type":"{Instant: \\"Instant\\", Timeline: \\"Timeline\\"}","source":{"line":27,"path":"src/_Core/Enums.luau"}},{"name":"HitboxType","desc":"Passed as `HitboxConfig.HitboxType`. `Partial` (default) slices whatever the hitbox finds;\\n`Whole` returns parts the hitbox fully contains untouched, with no slicing.","lua_type":"{Whole: \\"Whole\\", Partial: \\"Partial\\"}","source":{"line":34,"path":"src/_Core/Enums.luau"}},{"name":"QueryType","desc":"Passed as `HitboxConfig.QueryType`. Mirrors Roblox\'s own spatial query kinds. `Box`/`Region`\\nrun through the Octree + an exact box/AABB test, `Sphere` through the Octree + a distance\\ntest, and `Raycast` casts directly through the engine (single closest hit - see the README\'s\\nRaycast caveat).","lua_type":"{Raycast: \\"Raycast\\", Box: \\"Box\\", Sphere: \\"Sphere\\", Region: \\"Region\\"}","source":{"line":43,"path":"src/_Core/Enums.luau"}},{"name":"Effects","desc":"Keys into `ShatterConfig.Effects`. See [docs/effects](https://mkl48.github.io/Facet/effects) for\\nthe full config shape each one reads:\\n\\n- `Explode = {Radius: number}` - pushes the voxel outward from the Shatter origin.\\n- `Anchored = boolean` - sets the produced part\'s `Anchored` directly.\\n- `Chunk = boolean | {BreakSpeed: number?, BreakRadius: number?}` - welds every voxel a\\n  Shatter call produced (Partial *and* Extra) into one unanchored rigid assembly, so the\\n  remainder of a building falls as a single piece once its support is cut away, instead of\\n  every voxel tumbling apart individually. A weld breaks - detaching that piece and everything\\n  within `BreakRadius` studs of it (default `4`) - the moment its relative impact speed against\\n  whatever it hit reaches `BreakSpeed` studs/sec (default `40`), so the assembly fractures into\\n  smaller chunks on a hard enough landing instead of staying one rigid lump forever.\\n- `Slice = {Normal: Vector3?, Speed: number?}` - splits voxels either side of a plane (through\\n  the Shatter origin, facing `Normal`) apart along that normal at `Speed` studs/sec.\\n- `Blackhole = {Position: Vector3?, Duration: number?}` - tweens the voxel into `Position`\\n  while shrinking it to nothing, then destroys/releases it.\\n- `Whitehole = {Position: Vector3?, Speed: number?}` - launches the voxel directly away from\\n  `Position` at `Speed` studs/sec (like `Explode`, but a fixed point and speed instead of a\\n  radius).\\n- `Scatter = {Speed: number?}` - launches the voxel in a random direction at `Speed` studs/sec.\\n- `Shrink = {Duration: number?}` - tweens the voxel\'s `Size` down to nothing over `Duration`\\n  seconds, then destroys/releases it.","lua_type":"{Explode: \\"Explode\\", Anchored: \\"Anchored\\", Chunk: \\"Chunk\\", Slice: \\"Slice\\", Blackhole: \\"Blackhole\\", Whitehole: \\"Whitehole\\", Scatter: \\"Scatter\\", Shrink: \\"Shrink\\"}","source":{"line":70,"path":"src/_Core/Enums.luau"}},{"name":"Cleanup","desc":"Passed as `ShatterConfig.Cleanup.Method`, or to `Voxel:Cleanup` directly. `Destroy` is instant;\\n`Fade` tweens `Transparency` to 1 then destroys; `Rebuild` tweens the voxel\'s `CFrame` back\\nto `OriginalCFrame` and never destroys it.","lua_type":"{Rebuild: \\"Rebuild\\", Fade: \\"Fade\\", Destroy: \\"Destroy\\"}","source":{"line":78,"path":"src/_Core/Enums.luau"}},{"name":"Event","desc":"Passed to `PendingResult:Next`. `NewVoxel` fires once, right after voxelization/Effects;\\n`Destroyed` fires once every `Partial` voxel from that call has actually been destroyed by\\nCleanup (never fires if `Cleanup` was `Rebuild` or unset).","lua_type":"{NewVoxel: \\"NewVoxel\\", Destroyed: \\"Destroyed\\"}","source":{"line":86,"path":"src/_Core/Enums.luau"}}],"types":[],"name":"Enums","desc":"Every string-enum Facet\'s config and Result objects use. Each one is also re-exported as a\\ntype off the top-level `Facet` module (`Facet.ControllerType`, `Facet.RuntimeType`, etc.), so\\nyou don\'t need to reach into `Facet.Enums` just to annotate a variable.","source":{"line":11,"path":"src/_Core/Enums.luau"}}')}}]);